+
+/* ─── Constants ─────────────────────────────────────────────────── */
+
+const REPO_ROOT = join(import.meta.dir, "..");
+const UPDATE_SCRIPT = join(REPO_ROOT, "scripts", "update-web-demo.sh");
+const FRANKENTUI_DIST = "/dp/frankentui/dist";
+const WEB_DEST = join(REPO_ROOT, "public", "web");
